changeSet.sql:
-- Alter system types
ALTER TYPE SystemType RENAME TO SystemType__;
CREATE TYPE SystemType AS ENUM ('NONE', 'ON_PREMISE', 'CLOUD', 'ETL', 'MA', 'COTS', 'HOME_GROWN');
ALTER TABLE systems ALTER COLUMN system_type type SystemType using system_type::text::SystemType;
DROP TYPE SystemType__;

ALTER TABLE systems ADD COLUMN version_number character varying (255) DEFAULT NULL;
